package org.sanosysalvos.config;

import org.springframework.amqp.core.Binding;
import org.springframework.amqp.core.BindingBuilder;
import org.springframework.amqp.core.Queue;
import org.springframework.amqp.core.QueueBuilder;
import org.springframework.amqp.core.TopicExchange;
import org.springframework.amqp.rabbit.config.SimpleRabbitListenerContainerFactory;
import org.springframework.amqp.rabbit.connection.ConnectionFactory;
import org.springframework.amqp.support.converter.Jackson2JsonMessageConverter;
import org.springframework.amqp.support.converter.MessageConverter;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

/**
 * Configuración de RabbitMQ para el Matching Service.
 *
 * Consume desde la cola "reporte-coincidencias-queue" publicada por el
 * microservicio de reportes mediante el patrón Outbox.
 *
 * Topología (espejo de la del reporte-service):
 *   Exchange (topic): reporte-exchange
 *       └── Queue durable: reporte-coincidencias-queue
 *               binding routing-key: reporte.nuevo
 */
@Configuration
public class RabbitMQConfig {

    @Value("${app.rabbitmq.exchange}")
    private String exchange;

    @Value("${app.rabbitmq.queue}")
    private String queue;

    @Value("${app.rabbitmq.routing-key}")
    private String routingKey;

    @Bean
    public TopicExchange reporteExchange() {
        return new TopicExchange(exchange, true, false);
    }

    @Bean
    public Queue reporteCoincidenciasQueue() {
        return QueueBuilder.durable(queue).build();
    }

    @Bean
    public Binding reporteBinding(Queue reporteCoincidenciasQueue, TopicExchange reporteExchange) {
        return BindingBuilder
                .bind(reporteCoincidenciasQueue)
                .to(reporteExchange)
                .with(routingKey);
    }

    /** Convierte automáticamente JSON ↔ objetos Java en los listeners */
    @Bean
    public MessageConverter jsonMessageConverter() {
        return new Jackson2JsonMessageConverter();
    }

    @Bean
    public SimpleRabbitListenerContainerFactory rabbitListenerContainerFactory(
            ConnectionFactory connectionFactory) {
        SimpleRabbitListenerContainerFactory factory = new SimpleRabbitListenerContainerFactory();
        factory.setConnectionFactory(connectionFactory);
        factory.setMessageConverter(jsonMessageConverter());
        return factory;
    }
}

package org.sanosysalvos.dto;

import com.fasterxml.jackson.annotation.JsonIgnoreProperties;
import java.time.LocalDate;
import java.time.LocalDateTime;

/**
 * DTO que representa el mensaje JSON publicado por el microservicio de reportes
 * en la cola RabbitMQ "reporte-coincidencias-queue".
 *
 * Corresponde al ReporteMascotaDTO del reporte-service enriquecido con
 * los campos de la mascota necesarios para el algoritmo de matching.
 */
@JsonIgnoreProperties(ignoreUnknown = true)
public class ReporteMascotaEventDto {

    private Integer idReporteMascota;
    private Integer idTipoReporte;
    private String descripcionTipoReporte;
    private Integer idEstatus;
    private String descripcionEstatus;
    private LocalDate fechaExtravio;
    private Integer idContacto;
    private String nombresContacto;
    private LocalDate fechaAvistamiento;
    private LocalDateTime fechaReporte;
    private Integer idMarcaDistintiva;
    private String descripcionMarcaDistintiva;
    private Integer idMascota;
    private String nombreMascota;

    // Campos de la mascota relevantes para el scoring
    private String raza;
    private String colorPrimario;
    private String colorSecundario;
    private String tamano;
    private Double latitud;
    private Double longitud;

    public Integer getIdReporteMascota() { return idReporteMascota; }
    public void setIdReporteMascota(Integer idReporteMascota) { this.idReporteMascota = idReporteMascota; }

    public Integer getIdTipoReporte() { return idTipoReporte; }
    public void setIdTipoReporte(Integer idTipoReporte) { this.idTipoReporte = idTipoReporte; }

    public String getDescripcionTipoReporte() { return descripcionTipoReporte; }
    public void setDescripcionTipoReporte(String descripcionTipoReporte) { this.descripcionTipoReporte = descripcionTipoReporte; }

    public Integer getIdEstatus() { return idEstatus; }
    public void setIdEstatus(Integer idEstatus) { this.idEstatus = idEstatus; }

    public String getDescripcionEstatus() { return descripcionEstatus; }
    public void setDescripcionEstatus(String descripcionEstatus) { this.descripcionEstatus = descripcionEstatus; }

    public LocalDate getFechaExtravio() { return fechaExtravio; }
    public void setFechaExtravio(LocalDate fechaExtravio) { this.fechaExtravio = fechaExtravio; }

    public Integer getIdContacto() { return idContacto; }
    public void setIdContacto(Integer idContacto) { this.idContacto = idContacto; }

    public String getNombresContacto() { return nombresContacto; }
    public void setNombresContacto(String nombresContacto) { this.nombresContacto = nombresContacto; }

    public LocalDate getFechaAvistamiento() { return fechaAvistamiento; }
    public void setFechaAvistamiento(LocalDate fechaAvistamiento) { this.fechaAvistamiento = fechaAvistamiento; }

    public LocalDateTime getFechaReporte() { return fechaReporte; }
    public void setFechaReporte(LocalDateTime fechaReporte) { this.fechaReporte = fechaReporte; }

    public Integer getIdMarcaDistintiva() { return idMarcaDistintiva; }
    public void setIdMarcaDistintiva(Integer idMarcaDistintiva) { this.idMarcaDistintiva = idMarcaDistintiva; }

    public String getDescripcionMarcaDistintiva() { return descripcionMarcaDistintiva; }
    public void setDescripcionMarcaDistintiva(String descripcionMarcaDistintiva) { this.descripcionMarcaDistintiva = descripcionMarcaDistintiva; }

    public Integer getIdMascota() { return idMascota; }
    public void setIdMascota(Integer idMascota) { this.idMascota = idMascota; }

    public String getNombreMascota() { return nombreMascota; }
    public void setNombreMascota(String nombreMascota) { this.nombreMascota = nombreMascota; }

    public String getRaza() { return raza; }
    public void setRaza(String raza) { this.raza = raza; }

    public String getColorPrimario() { return colorPrimario; }
    public void setColorPrimario(String colorPrimario) { this.colorPrimario = colorPrimario; }

    public String getColorSecundario() { return colorSecundario; }
    public void setColorSecundario(String colorSecundario) { this.colorSecundario = colorSecundario; }

    public String getTamano() { return tamano; }
    public void setTamano(String tamano) { this.tamano = tamano; }

    public Double getLatitud() { return latitud; }
    public void setLatitud(Double latitud) { this.latitud = latitud; }

    public Double getLongitud() { return longitud; }
    public void setLongitud(Double longitud) { this.longitud = longitud; }
}

package org.sanosysalvos.messaging;

import org.sanosysalvos.dto.ReporteMascotaEventDto;
import org.sanosysalvos.model.ReporteMascota;
import org.sanosysalvos.repository.ReporteMascotaRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.stereotype.Component;
import org.springframework.transaction.annotation.Transactional;

/**
 * Consumidor RabbitMQ del Matching Service.
 *
 * Escucha la cola "reporte-coincidencias-queue" donde el microservicio de reportes
 * publica los reportes públicos de mascotas mediante el patrón Outbox.
 *
 * Al recibir un mensaje, sincroniza (crea o actualiza) el registro en la tabla
 * local "reporte_mascota" para que el algoritmo de scoring pueda operarlo sin
 * depender de una llamada HTTP al servicio de reportes.
 */
@Component
public class ReporteMascotaConsumer {

    private static final Logger log = LoggerFactory.getLogger(ReporteMascotaConsumer.class);

    private final ReporteMascotaRepository reporteMascotaRepository;

    public ReporteMascotaConsumer(ReporteMascotaRepository reporteMascotaRepository) {
        this.reporteMascotaRepository = reporteMascotaRepository;
    }

    @RabbitListener(queues = "${app.rabbitmq.queue}")
    @Transactional
    public void recibirReporte(ReporteMascotaEventDto evento) {
        if (evento == null || evento.getIdReporteMascota() == null) {
            log.warn("[RabbitMQ] Mensaje recibido nulo o sin idReporteMascota, ignorando.");
            return;
        }

        log.info("[RabbitMQ] Mensaje recibido: idReporteMascota={}, tipo={}",
                evento.getIdReporteMascota(), evento.getDescripcionTipoReporte());

        ReporteMascota reporte = reporteMascotaRepository
                .findById(evento.getIdReporteMascota().longValue())
                .orElse(new ReporteMascota());

        reporte.setIdReporteMascota(evento.getIdReporteMascota().longValue());
        reporte.setRaza(evento.getRaza());

        // Se prioriza colorPrimario; si viene colorSecundario se concatena
        String color = evento.getColorPrimario();
        if (color != null && evento.getColorSecundario() != null && !evento.getColorSecundario().isBlank()) {
            color = color + " / " + evento.getColorSecundario();
        }
        reporte.setColor(color);

        reporte.setTamano(evento.getTamano());
        reporte.setLatitud(evento.getLatitud());
        reporte.setLongitud(evento.getLongitud());
        reporte.setFechaReporte(evento.getFechaReporte());

        reporteMascotaRepository.save(reporte);

        log.info("[RabbitMQ] ReporteMascota id={} sincronizado correctamente.", reporte.getIdReporteMascota());
    }
}

spring.application.name=matching-service
server.port=8083

spring.datasource.url=${MATCHING_DB_URL:jdbc:postgresql://localhost:5432/matching_db}
spring.datasource.username=${MATCHING_DB_USER:postgres}
spring.datasource.password=${MATCHING_DB_PASSWORD:postgres}
spring.datasource.driver-class-name=org.postgresql.Driver

spring.jpa.hibernate.ddl-auto=update
spring.jpa.show-sql=true
spring.jpa.properties.hibernate.format_sql=true

matching.notification.url=${MATCHING_NOTIFICATION_URL:}
matching.circuit-breaker.failure-threshold=${MATCHING_CB_FAILURE_THRESHOLD:3}
matching.circuit-breaker.retry-seconds=${MATCHING_CB_RETRY_SECONDS:60}

# RabbitMQ
spring.rabbitmq.host=${RABBITMQ_HOST:localhost}
spring.rabbitmq.port=${RABBITMQ_PORT:5672}
spring.rabbitmq.username=${RABBITMQ_USERNAME:guest}
spring.rabbitmq.password=${RABBITMQ_PASSWORD:guest}

# Configuracion de la cola del servicio de reportes
app.rabbitmq.exchange=reporte-exchange
app.rabbitmq.queue=reporte-coincidencias-queue
app.rabbitmq.routing-key=reporte.nuevo
